import{_ as a,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Upload Screenshots","description":"","frontmatter":{},"headers":[],"relativePath":"imports/upload-screenshots.md","filePath":"imports/upload-screenshots.md"}'),s={name:"imports/upload-screenshots.md"};function l(i,e,n,h,p,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="upload-screenshots" tabindex="-1">Upload Screenshots <a class="header-anchor" href="#upload-screenshots" aria-label="Permalink to &quot;Upload Screenshots&quot;">​</a></h1><p>Upload screenshots from the <strong>Imports</strong> page when you want the app to detect rows for review.</p><blockquote><p>Screenshot placeholder: import-stage-picker.png</p></blockquote><h2 id="before-you-upload" tabindex="-1">Before you upload <a class="header-anchor" href="#before-you-upload" aria-label="Permalink to &quot;Before you upload&quot;">​</a></h2><p>Choose the right context first:</p><ul><li>kingdom</li><li>alliance, when required</li><li>import type</li><li>event</li><li>event date</li><li>stage or total mode, when needed</li></ul><p>If the event uses stages, the page can also ask for:</p><ul><li>stage number</li><li>stage date</li></ul><h2 id="import-types" tabindex="-1">Import types <a class="header-anchor" href="#import-types" aria-label="Permalink to &quot;Import types&quot;">​</a></h2><p>You can upload screenshots for:</p><ul><li><strong>Alliance players / member list</strong></li><li><strong>Event results</strong></li><li><strong>Kingdom event results</strong></li></ul><p>The correct type changes which fields are required.</p><h2 id="stage-and-total-choices" tabindex="-1">Stage and total choices <a class="header-anchor" href="#stage-and-total-choices" aria-label="Permalink to &quot;Stage and total choices&quot;">​</a></h2><p>For multi-stage events, the page can show:</p><ul><li><strong>Stage Data</strong></li><li><strong>Total Data</strong></li></ul><p>Use the one that matches the screenshot. Alliance Brawl deserves extra care because its stage choice should be deliberate. See <a href="./../events/alliance-brawl.html">Alliance Brawl</a>.</p><h2 id="processor-choice" tabindex="-1">Processor choice <a class="header-anchor" href="#processor-choice" aria-label="Permalink to &quot;Processor choice&quot;">​</a></h2><p>If your role allows it, choose:</p><ul><li>Free Local Processing</li><li>Gemini</li></ul><p>The page also links straight to image-processing settings when you need to switch providers or add a Gemini key.</p><h2 id="what-happens-after-upload" tabindex="-1">What happens after upload <a class="header-anchor" href="#what-happens-after-upload" aria-label="Permalink to &quot;What happens after upload&quot;">​</a></h2><p>After a successful upload:</p><ul><li>the import appears in history</li><li>the review page opens</li><li>you can inspect, edit, rematch, ignore, or accept rows</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./choose-provider.html">Choose an Image-Processing Provider</a></li><li><a href="./review-rows.html">Review Import Rows</a></li><li><a href="./overview.html">How Screenshot Imports Work</a></li></ul>',25)])])}const m=a(s,[["render",l]]);export{u as __pageData,m as default};
